@Service
class ProfileService(
    private val userRepository: UserRepository
) {
    fun getUserProfile(username: String): Either<ProfileError, ProfileDTO> {
        return userRepository.findUserByUsername(username)
            ?.let { user ->
                Right(
                    ProfileDTO(
                        username = user.getUsername(),
                        bio = user.getBio() ?: "",
                        image = user.getImage() ?: "",
                        following = false
                    )
                )
            } ?: Left(ProfileError.UserNotFound)
    }

    fun followUser(currentUserId: Long, username: String): Either<ProfileError, ProfileDTO> {
        val currentUser = userRepository.findUserByIdOrThrow(currentUserId)
        val targetUser = userRepository.findUserByUsernameOrThrow(username)

        if (currentUserId == targetUser.getId()) {
            return Left(ProfileError.CannotFollowYourself)
        }

        currentUser.followUser(targetUser)
        return Right(currentUser.viewUserProfile(targetUser))
    }

    fun unfollowUser(currentUserId: Long, username: String): Either<ProfileError, ProfileDTO> {
        val currentUser = userRepository.findUserByIdOrThrow(currentUserId)
        val targetUser = userRepository.findUserByUsernameOrThrow(username)

        currentUser.unfollowUser(targetUser)
        return Right(currentUser.viewUserProfile(targetUser))
    }

    fun viewUserProfile(currentUserId: Long, username: String): Either<ProfileError, ProfileDTO> {
        return try {
            val currentUser = userRepository.findUserByIdOrThrow(currentUserId)
            val targetUser = userRepository.findUserByUsernameOrThrow(username)
            Right(currentUser.viewUserProfile(targetUser))
        } catch (e: Exception) {
            Left(ProfileError.UnknownError)
        }
    }
}

private fun User.viewUserProfile(profile: Profile): ProfileDTO {
    val userProfile = this.viewUserProfile(profile)
    return ProfileDTO(
        username = userProfile.getUsername(),
        bio = userProfile.getBio() ?: "",
        image = userProfile.getImage() ?: "",
        following = userProfile.getFollowing()
    )
}

