            throw NotAuthorizedException("You are not the author of this article")
        }
        val updatedArticle = (article as ArticleEntity).apply {
            this.body = form.body ?: this.body
            this.description = form.description ?: this.description
        }
        val savedArticle = articleRepository.saveArticle(updatedArticle)
        return savedArticle.toDTO(false, userRepository.findUserByIdOrThrow(userId).username, false)
