import java.time.Instant

class ArticleService(
    private val userRepository: ReadOnlyUserRepository,
    private val articleRepository: ArticleRepository
) {
    fun saveNewUserArticle(userId: Long, form: ArticleCreateForm): ArticleDTO {
        val user = userRepository.findUserByIdOrThrow(userId)
        val article = articleRepository.saveNewArticle(user, form)
        return toArticleDTO(article, user)
    }

    fun deleteArticleBySlug(userId: Long, slug: String) {
        val user = userRepository.findUserByIdOrThrow(userId)
        val article = articleRepository.findArticleBySlugOrThrow(slug)
        if (!article.isCreatedBy(user)) {
            throw NotAuthorizedException("You are not the author of this article")
        }
        articleRepository.deleteArticle(article)
    }

    fun updateArticleBySlug(userId: Long, slug: String, form: ArticleUpdateForm): ArticleDTO {
        val user = userRepository.findUserByIdOrThrow(userId)
        val article = articleRepository.findArticleBySlugOrThrow(slug)
        if (!article.isCreatedBy(user)) {
            throw NotAuthorizedException("You are not the author of this article")
        }
        article.apply {
            form.title?.let { article.setTitle(it) }
            form.description?.let { article.setDescription(it) }
            form.body?.let { article.setBody(it) }
        }
        val updatedArticle = articleRepository.saveArticle(article)
        return toArticleDTO(updatedArticle, user)
    }

    fun findArticleBySlug(userId: Long?, slug: String): ArticleDTO {
        val article = articleRepository.findArticleBySlugOrThrow(slug)
        val currentUser = userId?.let { userRepository.findUserByIdOrThrow(it) }
        return toArticleDTO(article, currentUser)
    }

    private fun toArticleDTO(article: Article, currentUser: User?): ArticleDTO {
        val isFavorited = currentUser?.isFavoriteArticle(article) ?: false
        val isFollowing = currentUser?.isFollowing(article.author) ?: false
        return ArticleDTO(
            slug = article.slug,
            title = article.getTitle(),
            description = article.getDescription(),
            body = article.body,
            tagList = article.tagList.map { it.toString() },
            createdAt = article.createdAt,
            updatedAt = article.updatedAt,
            favorited = isFavorited,
            favoritesCount = article.favoritesCount,
            author = toProfileDTO(article.author, isFollowing)
        )
    }

    private fun toProfileDTO(profile: Profile, following: Boolean): ProfileDTO {
        return ProfileDTO(
            username = profile.username,
            bio = profile.bio ?: "",
            image = profile.image ?: "",
            following = following
        )
    }

    private fun Article.setTitle(title: String) {
        (this as? ArticleEntityAdapter)?.setTitle(title)
    }

    private fun Article.setDescription(description: String) {
        (this as? ArticleEntityAdapter)?.setDescription(description)
    }

    private fun Article.setBody(body: String) {
        (this as? ArticleEntityAdapter)?.setBody(body)
    }

    private fun Article.getTitle(): String {
        return (this as? ArticleEntityAdapter)?.getTitle() ?: ""
    }

    private fun Article.getDescription(): String {
        return (this as? ArticleEntityAdapter)?.getDescription() ?: ""
    }

    private interface ArticleEntityAdapter : Article {
        fun setTitle(title: String)
        fun getTitle(): String
        fun setDescription(description: String)
        fun getDescription(): String
    }
}

